import{_ as a,o as e,c as r,ag as i}from"./chunks/framework.C6K0jwmI.js";const u=JSON.parse('{"title":"セルフオーダー画面","description":"","frontmatter":{"title":"セルフオーダー画面"},"headers":[],"relativePath":"tenant/17-customer.md","filePath":"tenant/17-customer.md"}'),l={name:"tenant/17-customer.md"};function d(o,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="_17-セルフオーダー画面" tabindex="-1">17. セルフオーダー画面 <a class="header-anchor" href="#_17-セルフオーダー画面" aria-label="Permalink to &quot;17. セルフオーダー画面&quot;">​</a></h1><p>セルフオーダー画面は、お客様がテーブルQRコードから開く注文画面です。店舗スタッフは、表示内容と注文の流れを理解しておくと問い合わせ対応がしやすくなります。</p><h2 id="お客様の注文手順" tabindex="-1">お客様の注文手順 <a class="header-anchor" href="#お客様の注文手順" aria-label="Permalink to &quot;お客様の注文手順&quot;">​</a></h2><ol><li>テーブルのQRコードをスマートフォンで読み取ります。</li><li>メニューを選びます。</li><li>数量やオプションを選択します。</li><li>カート内容を確認します。</li><li>注文を送信します。</li><li>必要に応じてスタッフ呼び出しやAIウェイターを利用します。</li></ol><h2 id="店舗側で確認すること" tabindex="-1">店舗側で確認すること <a class="header-anchor" href="#店舗側で確認すること" aria-label="Permalink to &quot;店舗側で確認すること&quot;">​</a></h2><ul><li>QRコードが正しいテーブルに貼られていること</li><li>メニュー、価格、写真、売り切れ状態が正しいこと</li><li>注文がKDSとレジに反映されること</li><li>多言語表示の内容が大きくずれていないこと</li></ul><h2 id="aiウェイター" tabindex="-1">AIウェイター <a class="header-anchor" href="#aiウェイター" aria-label="Permalink to &quot;AIウェイター&quot;">​</a></h2><p>お客様はメニューについて質問できます。アレルギー、提供可否、価格など重要な内容は、店舗スタッフが最終確認してください。</p><h2 id="スタッフ呼び出し" tabindex="-1">スタッフ呼び出し <a class="header-anchor" href="#スタッフ呼び出し" aria-label="Permalink to &quot;スタッフ呼び出し&quot;">​</a></h2><p>お客様から呼び出しが入った場合は、店舗のルールに従って対応してください。呼び出し内容が分かる場合は、先に内容を確認してから向かうとスムーズです。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>メニューが表示されない</td><td>QRコード、店舗設定、メニュー公開状態を確認してください。</td></tr><tr><td>注文できない</td><td>Wi-Fi、売り切れ状態、テーブル開放状態を確認してください。</td></tr><tr><td>表示言語が違う</td><td>画面上の言語切替を確認してください。</td></tr><tr><td>金額が違う</td><td>商品価格、オプション、税区分を確認してください。</td></tr></tbody></table>',12)])])}const m=a(l,[["render",d]]);export{u as __pageData,m as default};
